create extension if not exists pgcrypto;
create table if not exists public.products(id bigint primary key,name text not null,category text not null,unit text not null check(unit in('kg','un')),price numeric(12,2) not null check(price>=0),stock numeric(12,3) not null default 0 check(stock>=0),emoji text default '🌿',updated_at timestamptz not null default now());
create table if not exists public.sales(id bigint generated by default as identity primary key,sale_number bigint generated by default as identity unique,subtotal numeric(12,2) not null,discount numeric(12,2) not null default 0,total numeric(12,2) not null,payment text not null,status text not null default 'completed' check(status in('completed','cancelled')),created_at timestamptz not null default now(),created_by uuid references auth.users(id),cancelled_at timestamptz,cancelled_by uuid references auth.users(id),cancel_reason text);
create table if not exists public.sale_items(id bigint generated by default as identity primary key,sale_id bigint not null references public.sales(id),product_id bigint not null references public.products(id),name text not null,qty numeric(12,3) not null check(qty>0),price numeric(12,2) not null,unit text not null);
create table if not exists public.store_settings(id integer primary key default 1 check(id=1),pix_key text,merchant_name text default 'EMPORIO LOURENCO',merchant_city text default 'SAO PAULO',updated_at timestamptz not null default now());
insert into public.store_settings(id) values(1) on conflict do nothing;
alter table public.products enable row level security; alter table public.sales enable row level security; alter table public.sale_items enable row level security; alter table public.store_settings enable row level security;
create policy "pdv products" on public.products for all to authenticated using(true) with check(true);
create policy "pdv sales read" on public.sales for select to authenticated using(true);
create policy "pdv items read" on public.sale_items for select to authenticated using(true);
create policy "pdv settings" on public.store_settings for all to authenticated using(true) with check(true);
grant select,insert,update on public.products to authenticated; grant select on public.sales,public.sale_items to authenticated; grant select,insert,update on public.store_settings to authenticated;
create or replace function public.complete_sale(p_items jsonb,p_discount numeric,p_payment text) returns bigint language plpgsql security definer set search_path=public as $$
declare sid bigint; sub numeric:=0; item jsonb; prod products%rowtype; q numeric;
begin if auth.uid() is null then raise exception 'Autenticação obrigatória'; end if; if jsonb_array_length(p_items)=0 then raise exception 'Venda sem itens'; end if;
for item in select * from jsonb_array_elements(p_items) loop q:=(item->>'qty')::numeric; select * into prod from products where id=(item->>'id')::bigint for update; if not found or prod.stock<q then raise exception 'Estoque insuficiente'; end if; sub:=sub+prod.price*q; end loop;
insert into sales(subtotal,discount,total,payment,created_by) values(sub,least(greatest(p_discount,0),sub),sub-least(greatest(p_discount,0),sub),p_payment,auth.uid()) returning id into sid;
for item in select * from jsonb_array_elements(p_items) loop q:=(item->>'qty')::numeric; update products set stock=stock-q,updated_at=now() where id=(item->>'id')::bigint returning * into prod; insert into sale_items(sale_id,product_id,name,qty,price,unit) values(sid,prod.id,prod.name,q,prod.price,prod.unit); end loop; return sid; end $$;
create or replace function public.cancel_sale(p_sale_id bigint,p_reason text) returns void language plpgsql security definer set search_path=public as $$
declare s sales%rowtype; item sale_items%rowtype; begin if auth.uid() is null then raise exception 'Autenticação obrigatória'; end if; select * into s from sales where id=p_sale_id for update; if not found then raise exception 'Venda não encontrada'; end if; if s.status='cancelled' then raise exception 'Venda já cancelada'; end if; if length(trim(coalesce(p_reason,'')))<3 then raise exception 'Informe o motivo'; end if; for item in select * from sale_items where sale_id=p_sale_id loop update products set stock=stock+item.qty,updated_at=now() where id=item.product_id; end loop; update sales set status='cancelled',cancelled_at=now(),cancelled_by=auth.uid(),cancel_reason=trim(p_reason) where id=p_sale_id; end $$;
grant execute on function public.complete_sale(jsonb,numeric,text) to authenticated; grant execute on function public.cancel_sale(bigint,text) to authenticated;
